@@ -12,6 +12,8 @@ impl LockStore {
     pub async fn create_lock(&self, req: &CreateLockRequest) -> Result<Lock, DbError> {
-        // BUG: was calling hex_to_bytes32_or_zero which silently truncated to 32 bytes
-        let pk_bytes = hex_to_bytes32_or_zero(&req.pk_dilithium_hex);
+        // Use the full raw key bytes — do NOT hash or truncate.
+        // pk_dilithium is BYTEA and must hold the complete Dilithium public key
+        // (1312 bytes for Dilithium2, 1952 bytes for Dilithium3).
+        let pk_bytes: &[u8] = &req.pk_dilithium;
+        if pk_bytes.len() < 1312 {
+            return Err(DbError::Validation(format!(
+                "pk_dilithium too short: got {} bytes, expected >= 1312",
+                pk_bytes.len()
+            )));
+        }

         let row = sqlx::query_as::<_, Lock>(
             r#"
             INSERT INTO locks (pk_dilithium, owner, status)
             VALUES ($1, $2, 'pending')
             RETURNING *
             "#,
         )
-        .bind(&pk_bytes[..])
+        .bind(pk_bytes)
         .bind(&req.owner)
         .fetch_one(&self.pool)
         .await
         .map_err(DbError::Sqlx)?;

+        // Invariant check: confirm the DB round-tripped the full key length.
+        if row.pk_dilithium.len() < 1312 {
+            return Err(DbError::Validation(format!(
+                "pk_dilithium persisted as {} bytes — write was truncated",
+                row.pk_dilithium.len()
+            )));
+        }
+
         Ok(row)
     }
 }
